module multi_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] product_reg;
    reg [7:0] multiplicand;
    reg [7:0] multiplier;
    integer i;

    always @(*) begin
        multiplicand = A;
        multiplier = B;
        product_reg = 16'd0;
        for (i = 0; i < 8; i = i + 1) begin
            if (multiplier[i]) begin
                product_reg = product_reg + (multiplicand << i);
            end
        end
    end

    assign product = product_reg;

endmodule
